import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../data/api';

const s = {
  page: { padding: '2rem', maxWidth: '900px', margin: '0 auto' },
  back: { color: '#7c6af7', cursor: 'pointer', marginBottom: '1.5rem', fontSize: '0.9rem', background: 'none', border: 'none' },
  title: { fontSize: '1.8rem', fontWeight: 700, color: '#fff', marginBottom: '0.3rem' },
  desc: { color: '#888', marginBottom: '2rem' },
  tabs: { display: 'flex', gap: '0.5rem', marginBottom: '2rem' },
  tab: { padding: '0.5rem 1.2rem', borderRadius: '20px', border: '1px solid #2a2a4a', cursor: 'pointer', fontSize: '0.9rem', background: 'none', color: '#888' },
  activeTab: { background: '#7c6af7', color: '#fff', border: '1px solid #7c6af7' },
  section: { marginBottom: '2rem' },
  sectionTitle: { color: '#7c6af7', fontWeight: 600, marginBottom: '1rem', fontSize: '1rem', textTransform: 'uppercase', letterSpacing: '0.05em' },
  list: { display: 'flex', flexDirection: 'column', gap: '0.75rem' },
  item: { background: '#1a1a2e', border: '1px solid #2a2a4a', borderRadius: '10px', padding: '1rem 1.25rem', cursor: 'pointer', display: 'flex', justifyContent: 'space-between', alignItems: 'center' },
  itemTitle: { color: '#e0e0e0', fontWeight: 500 },
  badge: { padding: '0.2rem 0.6rem', borderRadius: '20px', fontSize: '0.75rem', fontWeight: 600 },
  actions: { display: 'flex', gap: '0.75rem', marginTop: '1.5rem' },
  btn: { padding: '0.6rem 1.4rem', borderRadius: '8px', border: 'none', cursor: 'pointer', fontWeight: 600, fontSize: '0.9rem' },
};

const diffColors = { easy: '#4caf50', medium: '#ff9800', hard: '#f44336' };
const levelOrder = ['beginner', 'intermediate', 'advanced'];

export default function CoursePage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [course, setCourse] = useState(null);
  const [activeLevel, setActiveLevel] = useState('beginner');

  useEffect(() => { api.get(`/courses/${id}`).then(r => setCourse(r.data)); }, [id]);

  if (!course) return <div style={{ color: '#fff', padding: '2rem' }}>Loading...</div>;

  const level = course.levels.find(l => l.name === activeLevel);

  return (
    <div style={s.page}>
      <button style={s.back} onClick={() => navigate('/')}>← Back to Courses</button>
      <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '0.3rem' }}>
        <span style={{ fontSize: '2rem' }}>{course.icon}</span>
        <div style={s.title}>{course.title}</div>
      </div>
      <div style={s.desc}>{course.description}</div>

      <div style={s.tabs}>
        {levelOrder.map(l => (
          <button key={l} style={activeLevel === l ? { ...s.tab, ...s.activeTab } : s.tab}
            onClick={() => setActiveLevel(l)}>
            {l.charAt(0).toUpperCase() + l.slice(1)}
          </button>
        ))}
      </div>

      {level && (
        <>
          <div style={s.section}>
            <div style={s.sectionTitle}>📚 Topics</div>
            <div style={s.list}>
              {level.topics.map(t => (
                <div key={t._id} style={s.item}>
                  <span style={s.itemTitle}>{t.title}</span>
                  <span style={{ color: '#888', fontSize: '0.8rem' }}>{t.language}</span>
                </div>
              ))}
            </div>
          </div>

          <div style={s.section}>
            <div style={s.sectionTitle}>🧩 Problems</div>
            <div style={s.list}>
              {level.problems.map(p => (
                <div key={p._id} style={s.item} onClick={() => navigate(`/problem/${id}/${activeLevel}/${p._id}`)}>
                  <span style={s.itemTitle}>{p.title}</span>
                  <span style={{ ...s.badge, background: diffColors[p.difficulty] + '22', color: diffColors[p.difficulty] }}>{p.difficulty}</span>
                </div>
              ))}
            </div>
          </div>

          <div style={s.actions}>
            <button style={{ ...s.btn, background: '#7c6af7', color: '#fff' }}
              onClick={() => navigate(`/quiz/${id}/${activeLevel}`)}>
              🎯 Take Quiz
            </button>
          </div>
        </>
      )}
    </div>
  );
}
